// Category Management UI Contract
// Files: src/screens/CategoriesScreen.tsx, src/components/categories/CategoryList.tsx, src/components/categories/CategoryForm.tsx

// Import from '@/screens'
export function CategoriesScreen(): React.ReactElement;

// Import from '@/components/categories'
export interface CategoryListProps {
  categories: Category[];
  entryCounts?: Record<string, number>;
  isLoading?: boolean;
  onCategoryPress: (category: Category) => void;
  onCreatePress: () => void;
  onRefresh?: () => void;
  refreshing?: boolean;
}
export function CategoryList(props: CategoryListProps): React.ReactElement;

export interface CategoryFormProps {
  visible: boolean;
  onClose: () => void;
  category: Category | null;
  entryCount?: number;
  isSaving?: boolean;
  isDeleting?: boolean;
  onSubmit: (data: CreateCategoryInput | UpdateCategoryInput) => void;
  onDelete?: (categoryId: string) => void;
  onReassignEntries?: (fromCategoryId: string, toCategoryId: string) => void;
  otherCategories?: Category[];
  hasActiveTimer?: boolean;
  onStopTimer?: () => void;
}
export function CategoryForm(props: CategoryFormProps): React.ReactElement;

// Behavior notes:
// - CategoryList shows cards with color swatch, name, type badge, and entry count
// - CategoryForm modal validates with CreateCategorySchema (create) or UpdateCategorySchema (edit)
// - All three fields (name, color, type) are REQUIRED for creation
// - Delete warns about affected entries and offers reassignment to another category
// - ON DELETE SET NULL behavior means entries are never lost, just become uncategorized
// - Active timer on category blocks deletion until timer is stopped
